+        rows.iter()
+            .map(|r| SearchResult {
+                id: r.id,
+                subject: r.subject.clone(),
+                body_snippet: truncate_body(&r.subject, 200),
+                sender_name: r.from.clone(),
+                created: ts_display(r.created_ts),
+                importance: r.importance.clone(),
+                thread_id: r.thread_id.clone().unwrap_or_default(),
